# %% nbs/deploy/run_cmd.ipynb 2
import subprocess
import sys

from .config import get_server_ip, load_deploy_config

# %% nbs/deploy/run_cmd.ipynb 3
def main():
    if len(sys.argv) < 2:
        print("Usage: remote-run-cmd <command...>", file=sys.stderr)
        sys.exit(1)

    cmd = " ".join(sys.argv[1:])
    config = load_deploy_config()
    ip = get_server_ip(config["server"]["name"])
    repo_path = config["repo"]["path"]

    # Run via SSH, streaming output directly (no capture)
    result = subprocess.run(
        ["ssh", "-o", "StrictHostKeyChecking=no", "-t",
         f"root@{ip}",
         f"cd {repo_path} && {cmd}"],
    )
    sys.exit(result.returncode)
